<template>
  <view class="page">
    <view class="brand">
      <text class="title">管理后台登录</text>
      <text class="hint">使用服务端配置的管理员账号</text>
    </view>

    <view class="form">
      <view class="field">
        <text class="label">账号</text>
        <input
          class="input"
          v-model="username"
          placeholder="管理员账号"
          placeholder-class="ph"
        />
      </view>
      <view class="field">
        <text class="label">密码</text>
        <input
          class="input"
          v-model="password"
          password
          placeholder="密码"
          placeholder-class="ph"
        />
      </view>
      <button class="btn" :loading="loading" @click="onSubmit">登录</button>
    </view>

    <text class="foot">默认账号密码见后端环境变量 ADMIN_USER / ADMIN_PASS</text>
  </view>
</template>

<script setup>
import { ref } from 'vue';
import { onShow } from '@dcloudio/uni-app';
import { adminLogin, getAdminToken, adminAuthVerify } from '@/common/api/adminApi.js';

const username = ref('');
const password = ref('');
const loading = ref(false);

async function tryEnterWithToken() {
  if (!getAdminToken()) return;
  try {
    await adminAuthVerify();
    uni.redirectTo({ url: '/pages/admin/admin' });
  } catch {
    // Token 无效则留在登录页
  }
}

onShow(() => {
  tryEnterWithToken();
});

const onSubmit = async () => {
  if (!username.value.trim() || !password.value) {
    uni.showToast({ title: '请填写账号密码', icon: 'none' });
    return;
  }
  loading.value = true;
  try {
    await adminLogin(username.value, password.value);
    uni.showToast({ title: '登录成功', icon: 'success' });
    setTimeout(() => {
      uni.redirectTo({ url: '/pages/admin/admin' });
    }, 400);
  } catch (e) {
    uni.showToast({ title: e.message || '登录失败', icon: 'none' });
  } finally {
    loading.value = false;
  }
};
</script>

<style lang="scss" scoped>
.page {
  min-height: 100vh;
  background: linear-gradient(180deg, #023993 0%, #0a4cb5 35%, #f5f6f8 35%);
  padding: 80rpx 48rpx 48rpx;
  box-sizing: border-box;
}
.brand {
  margin-bottom: 72rpx;
  .title {
    font-size: 44rpx;
    font-weight: 700;
    color: #fff;
    display: block;
  }
  .hint {
    font-size: 26rpx;
    color: rgba(255, 255, 255, 0.85);
    margin-top: 16rpx;
    display: block;
  }
}
.form {
  background: #fff;
  border-radius: 24rpx;
  padding: 48rpx 40rpx 56rpx;
  box-shadow: 0 12rpx 40rpx rgba(2, 57, 147, 0.12);
}
.field {
  margin-bottom: 36rpx;
  .label {
    font-size: 26rpx;
    color: #666;
    display: block;
    margin-bottom: 16rpx;
  }
  .input {
    height: 88rpx;
    padding: 0 28rpx;
    background: #f5f6f8;
    border-radius: 16rpx;
    font-size: 30rpx;
  }
  .ph {
    color: #bbb;
  }
}
.btn {
  margin-top: 24rpx;
  height: 96rpx;
  line-height: 96rpx;
  background: #023993;
  color: #fff;
  font-size: 32rpx;
  border-radius: 48rpx;
  border: none;
  &::after {
    border: none;
  }
}
.foot {
  display: block;
  text-align: center;
  font-size: 22rpx;
  color: #999;
  margin-top: 48rpx;
  padding: 0 20rpx;
  line-height: 1.5;
}
</style>
